 33→public class SiteUtils {
 34→    public static final String GB_EDITOR_NAME = "gutenberg";
 35→    public static final String AZTEC_EDITOR_NAME = "aztec";
 36→    public static final String WP_STORIES_CREATOR_NAME = "wp_stories_creator";
 37→    public static final String WP_STORIES_JETPACK_VERSION = "9.1";
 38→    public static final String WP_CONTACT_INFO_JETPACK_VERSION = "8.5";
 39→    public static final String WP_FACEBOOK_EMBED_JETPACK_VERSION = "9.0";
 40→    public static final String WP_INSTAGRAM_EMBED_JETPACK_VERSION = "9.0";
 41→    public static final String WP_LOOM_EMBED_JETPACK_VERSION = "9.0";
 42→    public static final String WP_SMARTFRAME_EMBED_JETPACK_VERSION = "10.2";
 43→    private static final int GB_ROLLOUT_PERCENTAGE_PHASE_1 = 100;
 44→    private static final int GB_ROLLOUT_PERCENTAGE_PHASE_2 = 100;
 45→
 46→    /**
 47→     * Migrate the old app-wide editor preference value to per-site setting. wpcom sites will make a network call
 48→     * and store the value on the backend. selfHosted sites just store the value in the local DB in FluxC
 49→     * <p>
 50→     * Strategy: Check if there is the old app-wide preference still available (v12.9 and before used it).
 51→     * -- 12.9 ON -> turn all sites ON in 13.0
 52→     * -- 12.9 OPTED OUT (were auto-opted in but turned it OFF) -> turn all sites OFF in 13.0
 53→     */
 54→    public static void migrateAppWideMobileEditorPreferenceToRemote(final AccountStore accountStore,
 55→                                                                    final SiteStore siteStore,
 56→                                                                    final Dispatcher dispatcher) {
 57→        // Skip if the user is not signed in
 58→        if (!FluxCUtils.isSignedInWPComOrHasWPOrgSite(accountStore, siteStore)) {
 59→            return;
 60→        }
 61→
 62→        // If the user is already in the rollout group, we can skip this the migration.
 63→        if (AppPrefs.isUserInGutenbergRolloutGroup()) {
 64→            return;
 65→        }
 66→
 67→        // -------- Rollout: Phase 2 -------
 68→        //
 69→        // If user has any Aztec enabled sites, we'll migrate their sites to Gutenberg and schedule showing popup.
 70→        if (atLeastOneSiteHasAztecEnabled(siteStore)) {
 71→            // Randomly pick the user in the rollout group
 72→            if (accountStore.getAccount().getUserId() % 100 >= (100 - GB_ROLLOUT_PERCENTAGE_PHASE_2)) {
 73→                if (!NetworkUtils.isNetworkAvailable(WordPress.getContext())) {
 74→                    // If the network is not available, abort. We can't update the remote setting.
 75→                    return;
 76→                }
 77→
 78→                for (SiteModel site : siteStore.getSites()) {
 79→                    // Show "phase 2" dialog on sites that get switched from aztec to gutenberg
 80→                    if (TextUtils.equals(site.getMobileEditor(), AZTEC_EDITOR_NAME)) {
 81→                        AppPrefs.setShowGutenbergInfoPopupPhase2ForNewPosts(site.getUrl(), true);
 82→                        // Will show the popup again, even if it was displayed in the past
 83→                        AppPrefs.setGutenbergInfoPopupDisplayed(site.getUrl(), false);
 84→                        continue;
 85→                    }
 86→
 87→                    // Show "phase 1" dialog on sites that get switched from "empty" (no pref) to gutenberg
 88→                    if (TextUtils.isEmpty(site.getMobileEditor())) {
 89→                        AppPrefs.setShowGutenbergInfoPopupForTheNewPosts(site.getUrl(), true);
 90→                    }
 91→                }
 92→
 93→                // Track and enable Gutenberg for all sites using a single network call. Ideally we would track this
 94→                // on the network response, but this would make this rollout even more complex.
 95→                // There might be some rare events when we register a site switched to Gutenberg which is actually
 96→                // still on Aztec.
 97→                trackGutenbergEnabledForNonGutenbergSites(siteStore,
 98→                        BlockEditorEnabledSource.ON_PROGRESSIVE_ROLLOUT_PHASE_2);
 99→                dispatcher.dispatch(SiteActionBuilder.newDesignateMobileEditorForAllSitesAction(
100→                        new DesignateMobileEditorForAllSitesPayload(SiteUtils.GB_EDITOR_NAME, false)));
101→
102→                // After enabling Gutenberg on these sites, we consider the user entered the rollout group
103→                AppPrefs.setUserInGutenbergRolloutGroup();
104→            }
105→        }
106→
107→        // -------- Rollout: Phase 1 -------
108→        //
109→        // Check if the user has been "randomly" selected to enter the rollout group.
110→        //
111→        // For self hosted sites, there are often one or two users, and the user id is probably 0, 1 in these cases.
112→        // If we exclude low ids, we won't get an not an homogeneous distribution over self hosted and WordPress.com
113→        // users, but the purpose of this is to do a progressive rollout, not an necessarily an homogeneous rollout.
114→        //
115→        // To exclude ids 0 and 1, to rollout for 10% users,
116→        // we'll use a test like `id % 100 >= 90` instead of `id % 100 < 10`.
117→        if (accountStore.getAccount().getUserId() % 100 >= (100 - GB_ROLLOUT_PERCENTAGE_PHASE_1)) {
118→            if (atLeastOneSiteHasAztecEnabled(siteStore)) {
119→                // If the user has opt-ed out from at least one of their site, then exclude them from the cohort
120→                return;
121→            }
122→
123→            if (!NetworkUtils.isNetworkAvailable(WordPress.getContext())) {
124→                // If the network is not available, abort. We can't update the remote setting.
125→                return;
126→            }
127→
128→            // Force the dialog to be shown on updated sites
129→            for (SiteModel site : siteStore.getSites()) {
130→                if (TextUtils.isEmpty(site.getMobileEditor())) {
131→                    AppPrefs.setShowGutenbergInfoPopupForTheNewPosts(site.getUrl(), true);
132→                }
133→            }
134→
135→            // Track and enable and  Gutenberg for all sites using a single network call. Ideally we would track this
136→            // on the network response, but this would make this rollout even more complex.
137→            // There might be some rare events when we register a site switched to Gutenberg which is actually
138→            // still on Aztec.
139→            trackGutenbergEnabledForNonGutenbergSites(siteStore,
140→                    BlockEditorEnabledSource.ON_PROGRESSIVE_ROLLOUT_PHASE_1);
141→            dispatcher.dispatch(SiteActionBuilder.newDesignateMobileEditorForAllSitesAction(
142→                    new DesignateMobileEditorForAllSitesPayload(SiteUtils.GB_EDITOR_NAME)));
143→
144→            // After enabling Gutenberg on these sites, we consider the user entered the rollout group
145→            AppPrefs.setUserInGutenbergRolloutGroup();
146→        }
147→
148→        if (!AppPrefs.isDefaultAppWideEditorPreferenceSet()) {
149→            return;
150→        }
151→        final boolean oldAppWidePreferenceValue = AppPrefs.isGutenbergDefaultForNewPosts();
152→
153→        if (oldAppWidePreferenceValue) {
154→            dispatcher.dispatch(SiteActionBuilder.newDesignateMobileEditorForAllSitesAction(
155→                    new DesignateMobileEditorForAllSitesPayload(SiteUtils.GB_EDITOR_NAME)));
156→        } else {
157→            dispatcher.dispatch(SiteActionBuilder.newDesignateMobileEditorForAllSitesAction(
158→                    new DesignateMobileEditorForAllSitesPayload(SiteUtils.AZTEC_EDITOR_NAME)));
159→        }
160→    }
161→
162→    private static void trackGutenbergEnabledForNonGutenbergSites(final SiteStore siteStore,
163→                                                                  final BlockEditorEnabledSource source) {
164→        for (SiteModel site : siteStore.getSites()) {
165→            if (!TextUtils.equals(site.getMobileEditor(), GB_EDITOR_NAME)) {
166→                AnalyticsUtils.trackWithSiteDetails(Stat.EDITOR_GUTENBERG_ENABLED, site, source.asPropertyMap());
167→            }
168→        }
169→    }
170→
171→    private static boolean atLeastOneSiteHasAztecEnabled(final SiteStore siteStore) {
172→        // We want to make sure to enable Gutenberg only on the sites they didn't opt-out.
173→        for (SiteModel site : siteStore.getSites()) {
174→            if (TextUtils.equals(site.getMobileEditor(), AZTEC_EDITOR_NAME)) {
175→                return true;
176→            }
177→        }
178→        return false;
179→    }
180→
181→    public static boolean enableBlockEditorOnSiteCreation(Dispatcher dispatcher, SiteStore siteStore,
182→                                                          int siteLocalSiteID) {
183→        SiteModel newSiteModel = siteStore.getSiteByLocalId(siteLocalSiteID);
184→        if (newSiteModel != null) {
185→            enableBlockEditor(dispatcher, newSiteModel);
186→            AnalyticsUtils.trackWithSiteDetails(Stat.EDITOR_GUTENBERG_ENABLED, newSiteModel,
187→                    BlockEditorEnabledSource.ON_SITE_CREATION.asPropertyMap());
188→            return true;
189→        }
190→        return false;
191→    }
192→
193→    public static void enableBlockEditor(Dispatcher dispatcher, SiteModel siteModel) {
194→        dispatcher.dispatch(SiteActionBuilder.newDesignateMobileEditorAction(
195→                new DesignateMobileEditorPayload(siteModel, GB_EDITOR_NAME)));
196→    }
197→
198→    public static void disableBlockEditor(Dispatcher dispatcher, SiteModel siteModel) {
199→        dispatcher.dispatch(SiteActionBuilder.newDesignateMobileEditorAction(
200→                new DesignateMobileEditorPayload(siteModel, AZTEC_EDITOR_NAME)));
201→    }
202→
203→    public static boolean isBlockEditorDefaultForNewPost(@Nullable SiteModel site) {
204→        if (site == null) {
205→            return true;
206→        }
207→        if (TextUtils.isEmpty(site.getMobileEditor())) {
208→            // Default to block editor when mobile editor setting is empty
209→            return true;
210→        } else {
211→            return alwaysDefaultToGutenberg(site) || site.getMobileEditor().equals(SiteUtils.GB_EDITOR_NAME);
212→        }
213→    }
214→
215→    public static boolean alwaysDefaultToGutenberg(SiteModel site) {
216→        return site.isWPCom() && !site.isWPComAtomic();
217→    }
218→
219→    public static String getSiteNameOrHomeURL(SiteModel site) {
220→        String siteName = site.getName();
221→        if (siteName == null) {
222→            return "";
223→        }
224→        if (siteName.trim().length() == 0) {
225→            siteName = getHomeURLOrHostName(site);
226→        }
227→        return siteName;
228→    }
229→
230→    public static String getHomeURLOrHostName(SiteModel site) {
231→        String homeURL = UrlUtils.removeScheme(site.getUrl());
232→        homeURL = StringUtils.removeTrailingSlash(homeURL);
233→        if (TextUtils.isEmpty(homeURL)) {
234→            return UrlUtils.getHost(site.getXmlRpcUrl());
235→        }
236→        return homeURL;
237→    }
238→
239→    /**
240→     * @return true if the site is WPCom or Jetpack and is not private
241→     */
242→    public static boolean isPhotonCapable(SiteModel site) {
243→        return SiteUtils.isAccessedViaWPComRest(site) && (!site.isPrivate() || site.isWPComAtomic());
244→    }
245→
246→    public static boolean isAccessedViaWPComRest(@NonNull SiteModel site) {
247→        return site.getOrigin() == SiteModel.ORIGIN_WPCOM_REST;
248→    }
249→
250→    public static String getSiteIconUrl(SiteModel site, int size) {
251→        return PhotonUtils.getPhotonImageUrl(site.getIconUrl(), size, size, PhotonUtils.Quality.HIGH,
252→                site.isPrivateWPComAtomic());
253→    }
254→
255→    public static ImageType getSiteImageType(boolean isP2, BlavatarShape shape) {
256→        ImageType type = ImageType.BLAVATAR;
257→        if (isP2) {
258→            switch (shape) {
259→                case SQUARE:
260→                    type = ImageType.P2_BLAVATAR;
261→                    break;
262→                case SQUARE_WITH_ROUNDED_CORNERES:
263→                    type = ImageType.P2_BLAVATAR_ROUNDED_CORNERS;
264→                    break;
265→                case CIRCULAR:
266→                    type = ImageType.P2_BLAVATAR_CIRCULAR;
267→                    break;
268→            }
269→        } else {
270→            switch (shape) {
271→                case SQUARE:
272→                    type = ImageType.BLAVATAR;
273→                    break;
274→                case SQUARE_WITH_ROUNDED_CORNERES:
275→                    type = ImageType.BLAVATAR_ROUNDED_CORNERS;
276→                    break;
277→                case CIRCULAR:
278→                    type = ImageType.BLAVATAR_CIRCULAR;
279→                    break;
280→            }
281→        }
282→        return type;
283→    }
284→
285→    public static SiteAccessibilityInfo getAccessibilityInfoFromSite(@NonNull SiteModel site) {
286→        SiteVisibility siteVisibility;
287→
288→        if (site.isPrivateWPComAtomic()) {
289→            siteVisibility = SiteVisibility.PRIVATE_ATOMIC;
290→        } else if (site.isPrivate()) {
291→            siteVisibility = SiteVisibility.PRIVATE;
292→        } else {
293→            siteVisibility = SiteVisibility.PUBLIC;
294→        }
295→
296→        return new SiteAccessibilityInfo(siteVisibility, isPhotonCapable(site));
297→    }
298→
299→    public static ArrayList<Integer> getCurrentSiteIds(SiteStore siteStore, boolean selfhostedOnly) {
300→        ArrayList<Integer> siteIDs = new ArrayList<>();
301→        List<SiteModel> sites = selfhostedOnly ? siteStore.getSitesAccessedViaXMLRPC() : siteStore.getSites();
302→        for (SiteModel site : sites) {
303→            siteIDs.add(site.getId());
304→        }
305→
306→        return siteIDs;
307→    }
308→
309→    /**
310→     * Checks if site Jetpack version is higher than limit version
311→     *
312→     * @param site
313→     * @param limitVersion minimal acceptable Jetpack version
314→     * @return
315→     */
316→    public static boolean checkMinimalJetpackVersion(SiteModel site, String limitVersion) {
317→        String jetpackVersion = site.getJetpackVersion();
318→        if (site.isUsingWpComRestApi() && site.isJetpackConnected() && !TextUtils.isEmpty(jetpackVersion)) {
319→            // Jetpack version field is sometimes "false" instead of a number on self-hosted sites that are no
320→            // longer active.
321→            if (jetpackVersion.equals("false")) {
322→                return false;
323→            }
324→            return VersionUtils.checkMinimalVersion(jetpackVersion, limitVersion);
325→        }
326→        return false;
327→    }
328→
329→    public static boolean checkMinimalWordPressVersion(SiteModel site, String minVersion) {
330→        return VersionUtils.checkMinimalVersion(site.getSoftwareVersion(), minVersion);
331→    }
332→
333→    public static boolean supportsStoriesFeature(SiteModel site, JetpackFeatureRemovalPhaseHelper helper) {
334→       return site != null && (site.isWPCom() || checkMinimalJetpackVersion(site, WP_STORIES_JETPACK_VERSION))
335→               && helper.shouldShowStoryPost();
336→    }
337→
338→    public static boolean supportsContactInfoFeature(SiteModel site) {
339→        return site != null && (site.isWPCom() || checkMinimalJetpackVersion(site, WP_CONTACT_INFO_JETPACK_VERSION));
340→    }
341→
342→    public static boolean supportsLayoutGridFeature(SiteModel site) {
343→        return site != null && (site.isWPCom() || site.isWPComAtomic());
344→    }
345→
346→    public static boolean supportsTiledGalleryFeature(SiteModel site) {
347→        return site != null && site.isWPCom();
348→    }
349→
350→    public static boolean supportsVideoPressFeature(SiteModel site) {
351→        return site != null && site.isWPCom();
352→    }
353→
354→    public static boolean supportsEmbedVariationFeature(SiteModel site, String minimalJetpackVersion) {
355→        return site != null && (site.isWPCom() || checkMinimalJetpackVersion(site, minimalJetpackVersion));
356→    }
357→
358→    public static boolean isNonAtomicBusinessPlanSite(@Nullable SiteModel site) {
359→        return site != null && !site.isAutomatedTransfer() && SiteUtils.hasNonJetpackBusinessPlan(site);
360→    }
361→
362→    public static boolean hasNonJetpackBusinessPlan(SiteModel site) {
363→        return site.getPlanId() == PlansConstants.BUSINESS_PLAN_ID;
364→    }
365→
366→    public static boolean onFreePlan(@NonNull SiteModel site) {
367→        return site.getPlanId() == PlansConstants.FREE_PLAN_ID;
368→    }
369→
370→    public static boolean onBloggerPlan(@NonNull SiteModel site) {
371→        return site.getPlanId() == PlansConstants.BLOGGER_PLAN_ONE_YEAR_ID
372→               || site.getPlanId() == PlansConstants.BLOGGER_PLAN_TWO_YEARS_ID;
373→    }
374→
375→    public static boolean hasFullAccessToContent(@Nullable SiteModel site) {
376→        return site != null && (site.isSelfHostedAdmin() || site.getHasCapabilityEditPages());
377→    }
378→
379→    // TODO: Inline this method when the legacy 'MySiteFragment' class is removed.
380→    public static boolean isScanEnabled(boolean scanPurchased, SiteModel site) {
381→        return scanPurchased && !site.isWPCom() && !site.isWPComAtomic();
382→    }
383→
384→    @NonNull
385→    public static FetchSitesPayload getFetchSitesPayload() {
386→        ArrayList<SiteFilter> siteFilters = new ArrayList<>();
387→        return new FetchSitesPayload(siteFilters, !BuildConfig.IS_JETPACK_APP);
388→    }
389→}
