 19→class JetpackFeatureCardHelper @Inject constructor(
 20→    private val analyticsTrackerWrapper: AnalyticsTrackerWrapper,
 21→    private val appPrefsWrapper: AppPrefsWrapper,
 22→    private val buildConfigWrapper: BuildConfigWrapper,
 23→    private val dateTimeUtilsWrapper: DateTimeUtilsWrapper,
 24→    private val jetpackFeatureRemovalPhaseHelper: JetpackFeatureRemovalPhaseHelper,
 25→    private val phaseThreeBlogPostLinkConfig: PhaseThreeBlogPostLinkConfig
 26→) {
 27→    fun shouldShowJetpackFeatureCard(): Boolean {
 28→        val isWordPressApp = !buildConfigWrapper.isJetpackApp
 29→        val exceedsShowFrequency = exceedsShowFrequencyAndResetJetpackFeatureCardLastShownTimestampIfNeeded()
 30→        return isWordPressApp && shouldShowJetpackFeatureCardInCurrentPhase() &&
 31→                !isJetpackCardHiddenByUser() && exceedsShowFrequency
 32→    }
 33→
 34→    private fun isJetpackCardHiddenByUser(): Boolean {
 35→        return jetpackFeatureRemovalPhaseHelper.getCurrentPhase()?.run {
 36→            appPrefsWrapper.getShouldHideJetpackFeatureCard(
 37→                this
 38→            )
 39→        } ?: false
 40→    }
 41→
 42→    fun shouldShowFeatureCardAtTop(): Boolean {
 43→        return when (jetpackFeatureRemovalPhaseHelper.getCurrentPhase()) {
 44→            is PhaseThree, PhaseSelfHostedUsers -> true
 45→            else -> false
 46→        }
 47→    }
 48→
 49→    private fun shouldShowJetpackFeatureCardInCurrentPhase(): Boolean {
 50→        return when (jetpackFeatureRemovalPhaseHelper.getCurrentPhase()) {
 51→            is PhaseThree, PhaseNewUsers, PhaseSelfHostedUsers -> true
 52→            else -> false
 53→        }
 54→    }
 55→
 56→    fun getCardContent(): UiString.UiStringRes? {
 57→        return when (jetpackFeatureRemovalPhaseHelper.getCurrentPhase()) {
 58→            is PhaseThree ->
 59→                UiString.UiStringRes(R.string.jetpack_feature_card_content_phase_three)
 60→            is PhaseNewUsers, PhaseSelfHostedUsers ->
 61→                UiString.UiStringRes(R.string.jetpack_feature_card_content_phase_self_hosted_and_new_users)
 62→            else -> null
 63→        }
 64→    }
 65→
 66→    private fun isSwitchToJetpackMenuCardHiddenByUser(): Boolean {
 67→        return jetpackFeatureRemovalPhaseHelper.getCurrentPhase()?.run {
 68→            appPrefsWrapper.getShouldHideSwitchToJetpackMenuCard(
 69→                this
 70→            )
 71→        } ?: false
 72→    }
 73→
 74→    fun track(stat: Stat) {
 75→        analyticsTrackerWrapper.track(
 76→            stat,
 77→            mapOf(PHASE to jetpackFeatureRemovalPhaseHelper.getCurrentPhase()?.trackingName)
 78→        )
 79→    }
 80→
 81→    fun getLearnMoreUrl(): String {
 82→        val url = phaseThreeBlogPostLinkConfig.getValue<String>()
 83→
 84→        if (url.isEmpty())
 85→            return url
 86→
 87→        return if (!url.contains(HOST)) {
 88→            "$HOST$url"
 89→        } else
 90→            url
 91→    }
 92→
 93→    @Suppress("ReturnCount")
 94→    private fun exceedsShowFrequencyAndResetJetpackFeatureCardLastShownTimestampIfNeeded(): Boolean {
 95→        val currentPhase = jetpackFeatureRemovalPhaseHelper.getCurrentPhase() ?: return false
 96→        val lastShownTimestamp = appPrefsWrapper.getJetpackFeatureCardLastShownTimestamp(currentPhase)
 97→        if (lastShownTimestamp == DEFAULT_LAST_SHOWN_TIMESTAMP) return true
 98→
 99→        val lastShownDate = Date(lastShownTimestamp)
100→        val daysPastOverlayShown = dateTimeUtilsWrapper.daysBetween(
101→            lastShownDate,
102→            Date(System.currentTimeMillis())
103→        )
104→
105→        val exceedsFrequency = daysPastOverlayShown >= FREQUENCY_IN_DAYS
106→        if (exceedsFrequency) {
107→            appPrefsWrapper.setJetpackFeatureCardLastShownTimestamp(currentPhase, DEFAULT_LAST_SHOWN_TIMESTAMP)
108→        }
109→        return exceedsFrequency
110→    }
111→
112→    fun shouldShowSwitchToJetpackMenuCard(): Boolean {
113→        return shouldShowSwitchToJetpackMenuCardInCurrentPhase() &&
114→                exceedsShowFrequencyAndResetSwitchToJetpackMenuLastShownTimestampIfNeeded() &&
115→                !isSwitchToJetpackMenuCardHiddenByUser()
116→    }
117→
118→    private fun shouldShowSwitchToJetpackMenuCardInCurrentPhase(): Boolean {
119→        return when (jetpackFeatureRemovalPhaseHelper.getCurrentPhase()) {
120→            is JetpackFeatureRemovalPhase.PhaseFour -> true
121→            else -> false
122→        }
123→    }
124→
125→    private fun exceedsShowFrequencyAndResetSwitchToJetpackMenuLastShownTimestampIfNeeded(): Boolean {
126→        val lastShownTimestamp = appPrefsWrapper.getSwitchToJetpackMenuCardLastShownTimestamp()
127→        if (lastShownTimestamp == DEFAULT_LAST_SHOWN_TIMESTAMP) return true
128→
129→        val lastShownDate = Date(lastShownTimestamp)
130→        val daysPastOverlayShown = dateTimeUtilsWrapper.daysBetween(
131→            lastShownDate,
132→            Date(System.currentTimeMillis())
133→        )
134→
135→        val exceedsFrequency = daysPastOverlayShown >= FREQUENCY_IN_DAYS
136→        if (exceedsFrequency) {
137→            appPrefsWrapper.setSwitchToJetpackMenuCardLastShownTimestamp(DEFAULT_LAST_SHOWN_TIMESTAMP)
138→        }
139→        return exceedsFrequency
140→    }
141→
142→    fun hideJetpackFeatureCard() {
143→        track(Stat.REMOVE_FEATURE_CARD_HIDE_TAPPED)
144→        jetpackFeatureRemovalPhaseHelper.getCurrentPhase()?.let {
145→            appPrefsWrapper.setShouldHideJetpackFeatureCard(it, true)
146→        }
147→    }
148→
149→    fun setJetpackFeatureCardLastShownTimeStamp(currentTimeMillis: Long) {
150→        track(Stat.REMOVE_FEATURE_CARD_REMIND_LATER_TAPPED)
151→        jetpackFeatureRemovalPhaseHelper.getCurrentPhase()?.let {
152→            appPrefsWrapper.setJetpackFeatureCardLastShownTimestamp(it, currentTimeMillis)
153→        }
154→    }
155→    fun hideSwitchToJetpackMenuCard() {
156→        track(Stat.REMOVE_FEATURE_CARD_HIDE_TAPPED)
157→        jetpackFeatureRemovalPhaseHelper.getCurrentPhase()?.let {
158→            appPrefsWrapper.setShouldHideSwitchToJetpackMenuCard(it, true)
159→        }
160→    }
161→    companion object {
162→        const val PHASE = "phase"
163→        const val FREQUENCY_IN_DAYS = 4
164→        const val DEFAULT_LAST_SHOWN_TIMESTAMP = 0L
165→        const val HOST = "https://"
166→    }
167→}
