 6→import org.wordpress.android.models.PublicizeConnection
 7→import org.wordpress.android.models.PublicizeService
 8→import org.wordpress.android.modules.IO_THREAD
 9→import org.wordpress.android.ui.publicize.services.PublicizeUpdateServicesV2
10→import org.wordpress.android.util.AppLog
11→import javax.inject.Inject
12→import javax.inject.Named
13→import kotlin.coroutines.resume
14→import kotlin.coroutines.suspendCoroutine
15→
16→/**
17→ * Returns a list of connections available for a user. See PublicizeConnectionList#getServiceConnectionsForUser
18→ */
19→class GetPublicizeConnectionsForUserUseCase @Inject constructor(
20→    @Named(IO_THREAD) private val ioDispatcher: CoroutineDispatcher,
21→    private val publicizeTableWrapper: PublicizeTableWrapper,
22→    private val publicizeUpdateServicesV2: PublicizeUpdateServicesV2,
23→) {
24→    suspend fun execute(siteId: Long, userId: Long, shouldForceUpdate: Boolean = true): List<PublicizeConnection> =
25→        withContext(ioDispatcher) {
26→            val allSupportedServices = if (shouldForceUpdate) {
27→                fetchServices(siteId)
28→            } else {
29→                publicizeTableWrapper.getServiceList().run {
30→                    ifEmpty { fetchServices(siteId) }
31→                }
32→            }.filter { it.status != PublicizeService.Status.UNSUPPORTED }
33→            val allConnectionsForSite = if (shouldForceUpdate) {
34→                fetchConnections(siteId)
35→            } else {
36→                publicizeTableWrapper.getConnectionsForSite(siteId).run {
37→                    ifEmpty { fetchConnections(siteId) }
38→                }
39→            }
40→            val connectionsForUser: List<PublicizeConnection> = allSupportedServices.map { service ->
41→                allConnectionsForSite.filter {
42→                    it.service.equals(service.id, true) && (it.isShared || it.userId.toLong() == userId)
43→                }
44→            }.flatten()
45→            connectionsForUser
46→        }
47→
48→    private suspend fun fetchServices(siteId: Long): List<PublicizeService> =
49→        suspendCoroutine { cont ->
50→            publicizeUpdateServicesV2.updateServices(
51→                siteId = siteId,
52→                success = { services -> cont.resume(services) },
53→                failure = {
54→                    AppLog.e(AppLog.T.SHARING, "Error updating publicize services", it)
55→                    cont.resume(emptyList())
56→                }
57→            )
58→        }
59→
60→    private suspend fun fetchConnections(siteId: Long): List<PublicizeConnection> =
61→        suspendCoroutine { cont ->
62→            publicizeUpdateServicesV2.updateConnections(
63→                siteId = siteId,
64→                success = { connections -> cont.resume(connections) },
65→                failure = {
66→                    AppLog.e(AppLog.T.SHARING, "Error updating publicize connections", it)
67→                    cont.resume(emptyList())
68→                }
69→            )
70→        }
71→}
