 223→                getActivity(), getSite(), new SiteSettingsListener() {
 224→                    @Override
 225→                    public void onSaveError(Exception error) {
 226→                        // no-op
 227→                    }
 228→
 229→                    @Override
 230→                    public void onFetchError(Exception error) {
 231→                        // no-op
 232→                    }
 233→
 234→                    @Override
 235→                    public void onSettingsUpdated() {
 236→                        // mEditPostActivityHook will be null if the fragment is detached
 237→                        if (getEditPostActivityHook() != null) {
 238→                            updatePostFormat(
 239→                                    mSiteSettings.getDefaultPostFormat());
