 243→                    @Override
 244→                    public void onSettingsSaved() {
 245→                        // no-op
 246→                    }
 247→
 248→                    @Override
 249→                    public void onCredentialsValidated(Exception error) {
 250→                        // no-op
 251→                    }
 252→                });
