 497→        switch (item.getItemId()) {
 498→            case CHOOSE_FEATURED_IMAGE_MENU_ID:
 499→                mFeaturedImageHelper.cancelFeaturedImageUpload(site, post, false);
 500→                launchFeaturedMediaPicker();
 501→                return true;
 502→            case REMOVE_FEATURED_IMAGE_UPLOAD_MENU_ID:
 503→            case REMOVE_FEATURED_IMAGE_MENU_ID:
 504→                mFeaturedImageHelper.cancelFeaturedImageUpload(site, post, false);
 505→                clearFeaturedImage();
 506→
 507→                mFeaturedImageHelper.trackFeaturedImageEvent(TrackableEvent.IMAGE_REMOVE_CLICKED, post.getId());
 508→
 509→                return true;
 510→            case RETRY_FEATURED_IMAGE_UPLOAD_MENU_ID:
 511→                retryFeaturedImageUpload(site, post);
 512→                return true;
 513→            default:
 514→                return false;
 515→        }
 516→    }
