 563→    @Override
 564→    @SuppressWarnings("deprecation")
 565→    public void onActivityResult(int requestCode, int resultCode, Intent data) {
 566→        super.onActivityResult(requestCode, resultCode, data);
 567→
 568→        if (data != null) {
 569→            Bundle extras;
 570→
 571→            switch (requestCode) {
 572→                case ACTIVITY_REQUEST_CODE_SELECT_CATEGORIES:
 573→                    extras = data.getExtras();
 574→                    if (extras != null && extras.containsKey(KEY_SELECTED_CATEGORY_IDS)) {
 575→                        @SuppressWarnings("unchecked")
 576→                        List<Long> categoryList = (ArrayList<Long>) extras.getSerializable(KEY_SELECTED_CATEGORY_IDS);
 577→                        PostAnalyticsUtilsKt.trackPostSettings(
 578→                                mAnalyticsTrackerWrapper, Stat.EDITOR_POST_CATEGORIES_ADDED);
 579→                        updateCategories(categoryList);
 580→                    }
 581→                    break;
 582→                case ACTIVITY_REQUEST_CODE_SELECT_TAGS:
 583→                    extras = data.getExtras();
 584→                    if (resultCode == RESULT_OK && extras != null) {
 585→                        String selectedTags = extras.getString(PostSettingsTagsActivity.KEY_SELECTED_TAGS);
 586→                        PostAnalyticsUtilsKt.trackPostSettings(mAnalyticsTrackerWrapper, Stat.EDITOR_POST_TAGS_CHANGED);
 587→                        updateTags(selectedTags);
 588→                    }
 589→                    break;
 590→                case RequestCodes.PAGE_PARENT:
 591→                    extras = data.getExtras();
 592→                    if (resultCode == Activity.RESULT_OK && extras != null) {
 593→                        long parentId = extras.getLong(EXTRA_PAGE_PARENT_ID_KEY, -1);
 594→                        if (parentId != -1L) {
 595→                            updateParent(parentId);
 596→                        }
 597→                    }
 598→            }
 599→        }
 600→    }
