194→    private suspend fun mapLoaded(): JetpackSocialUiState.Loaded {
195→        val shareMessage = jetpackSocialShareMessage.ifEmpty {
196→            getJetpackSocialShareMessageUseCase.execute(currentPost?.id ?: -1)
197→        }
198→        val socialSharingModel = postSocialSharingModelMapper.map(connections, shareLimit)
199→        return jetpackUiStateMapper.mapLoaded(
200→            connections = connections,
201→            shareLimit = shareLimit,
202→            socialSharingModel = socialSharingModel,
203→            onSubscribeClick = ::onJetpackSocialSubscribeClick,
204→            shareMessage = shareMessage,
205→            onShareMessageClick = ::onJetpackSocialMessageClick,
206→            onConnectionClick = ::onJetpackSocialConnectionClick,
207→            isPostPublished = isPostPublished(),
208→        )
209→    }
