294→    @VisibleForTesting
295→    fun onJetpackSocialConnectionClick(
296→        connection: PostSocialConnection,
297→        enabled: Boolean,
298→        jetpackSocialFlow: JetpackSocialFlow
299→    ) {
300→        jetpackSocialSharingTracker.trackConnectionToggled(jetpackSocialFlow, enabled)
301→        launch {
302→            // Update UI
303→            connections.firstOrNull { it.connectionId == connection.connectionId }?.let {
304→                it.isSharingEnabled = enabled
305→            }
306→            _jetpackSocialUiState.postValue(mapLoaded())
307→            // Update local post
308→            editPostRepository.updateAsync({ postModel ->
309→                val connectionId = connection.connectionId.toString()
310→                with(postModel.publicizeSkipConnectionsList.toMutableList()) {
