112→    fun shouldShowSwitchToJetpackMenuCard(): Boolean {
113→        return shouldShowSwitchToJetpackMenuCardInCurrentPhase() &&
114→                exceedsShowFrequencyAndResetSwitchToJetpackMenuLastShownTimestampIfNeeded() &&
115→                !isSwitchToJetpackMenuCardHiddenByUser()
116→    }
