 893→    private void updatePassword(String password) {
 894→        EditPostRepository editPostRepository = getEditPostRepository();
 895→        if (editPostRepository == null) return;
 896→
 897→        String trimmedPassword = password.trim();
 898→        Boolean isNewPasswordBlank = trimmedPassword.isEmpty();
 899→        String previousPassword = editPostRepository.getPassword();
 900→        Boolean isPreviousPasswordBlank = previousPassword.trim().isEmpty();
 901→
 902→        // Nothing to save
 903→        if (isNewPasswordBlank && isPreviousPasswordBlank) return;
 904→
 905→        // Save untrimmed password if not blank, else save empty string
 906→        String newPassword = isNewPasswordBlank ? trimmedPassword : password;
 907→
 908→        editPostRepository.updateAsync(postModel -> {
 909→            postModel.setPassword(newPassword);
 910→            return true;
 911→        }, (postModel, result) -> {
 912→            if (result == UpdatePostResult.Updated.INSTANCE) {
 913→                mPasswordTextView.setText(newPassword);
 914→            }
 915→            return null;
 916→        });
